  ('dietitian-moex-01283', 'dietitian', 'dietitian-moex-110-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於細胞色素P450（cytochromeP450）的敘述，下列何者錯誤？', '["結構含有血基質（heme），主要包含 monooxygenase（mixed-functionoxidase）", "除肝臟解毒，也參與固醇類荷爾蒙生成、膽酸合成與維生素D活化", "可從NADH或NADPH接受電子", "分布僅限於細胞內質網"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "4682e1f98de9", "answer_pdf_sha1": "0a3c7097368a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01284', 'dietitian', 'dietitian-moex-110-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者水解所釋出的自由能（ΔG）最多？', '["ATP", "甘油-3-磷酸（glycerol-3-phosphate）", "磷酸肌酸（creatinephosphate）", "磷酸烯醇丙酮酸（phosphoenolpyruvate）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "4682e1f98de9", "answer_pdf_sha1": "0a3c7097368a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01285', 'dietitian', 'dietitian-moex-110-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '酵素動力學（enzymekinetics）無法闡明酵素的何種性質？', '["酵素的一級結構", "酵素催化反應所需的輔酶", "酵素的反應速率和平衡常數", "酵素抑制劑的作用機制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "4682e1f98de9", "answer_pdf_sha1": "0a3c7097368a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01286', 'dietitian', 'dietitian-moex-110-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以酵素催化反應而言，相較於沒有酵素存在時，酵素約可加快多少倍數的反應速率？', '["約50～100倍", "約1,000～5,000倍", "約10,000～50,000倍", "106倍以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "4682e1f98de9", "answer_pdf_sha1": "0a3c7097368a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01287', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'essay', '急診病患黃先生，58 歲，身高 162 公分，通常體重 68 公斤。病史：糖
尿病、高血脂、高血壓，五年前因急性心肌梗塞入院放置支架，後續固
定追蹤並服藥：包括 metformin500mgTID及 rosuvastatin10mgQD 等。
因工作忙碌平日幾乎外食，常吃麵包、泡麵，少有機會吃蔬菜、水果，
每天至少喝兩大杯 750 mL 無糖茶飲料，平常血壓約 140/85 mmHg。最
近兩週體重增加至 80 公斤，大小腿浮腫且易喘、行動困難、睡覺無法平
躺。X光檢查發現心臟擴大，肺部肋間積水，抽血發現 Albumin3.4g/dL，
BUN 38 mg/dL，Creatinine 1.9 mg/dL，Na 131 mEq/L，K 4.4 mEq/L，N
端前腦利鈉肽（N-terminalpro-brainnatriureticpeptide,NT-proBNP）11756pg/mL，
心臟超音波檢查左心室射出分率（Left Ventricular Ejection Fraction,
LVEF）32%，給予利尿劑並住院治療心衰竭。請評估黃先生的營養問題，
分別敘述各項營養問題的解決方案，並針對黃先生使用的藥物給予營養
建議。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01288', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'essay', '臺灣人口老化邁入高齡社會，老人常見營養問題包括味覺、嗅覺減退、
血管彈性降低、記憶力減退、消化能力減弱、牙齒不好、唾液減少，試
述如何因應這些問題給予高齡患者飲食建議。（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01289', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'essay', '請 說 明 國 際 吞 嚥 困 難 飲 食 標 準 （ The International Dysphagia
StandardisationInitiative,IDDSI）對於食物及飲料之分級名稱、描述特徵、
適用的生理條件，並敘述以湯匙、叉子、針筒、筷子或手指評估食物及
飲料分級之測試方法，以及具體食物範例。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01290', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關Crohn''sdisease的敘述，下列何者正確？', '["是對小麥麩質過敏之疾病", "常出現傾食症候群的症狀", "是一種先天性酵素缺乏的疾病", "常出現腸黏膜發炎的症狀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01291', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據Academy of Nutrition and Dietetics與ASPEN的定義，在非計畫減重的狀況下，一個月體重 至少減輕多少以上，即為嚴重體重減輕，屬於營養不良的高危險群？', '["3%", "5%", "7.5%", "10%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01292', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '蔡小姐21歲，患有神經性厭食症，身高158公分，體重40公斤，平時偏食嚴重，只吃自己認為 熱量少不影響體重的食物，經常減少餐次，若多吃就會去催吐，平均每日攝食量約 1,100 大卡。 在進行營養診斷記錄時，下列敘述何者錯誤？', '["營養診斷之問題（Problem）：熱量攝取不足", "營養診斷之原因（Etiology）：<25%的熱量需求", "營養診斷之原因（Etiology）：經常減少餐次", "營養診斷之症狀（Signs）：BMI=16"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
